SELECT AVG(va.volatility_level) AS average_volatility
FROM volatility_assumptions va
INNER JOIN pricing_scenarios ps ON va.volatility_id = ps.volatility_id;

SELECT email, role, status
FROM trading_users
WHERE role = 'analyst' AND status = 'active';

SELECT AVG(market_cap) AS average_market_cap
FROM market_data
WHERE current_price > 100;

SELECT option_price 
FROM option_prices 
WHERE option_type = 'put' AND strike_price > 100;

SELECT *
FROM trading_strategies
WHERE created_by IN (
  SELECT DISTINCT generated_by
  FROM pricing_reports
);

SELECT option_type, MAX(strike_price) AS max_strike_price
FROM option_prices
GROUP BY option_type;

SELECT risk_id, option_id
FROM risk_analysis
WHERE option_id = 0;

SELECT AVG(volatility_level) AS AverageVolatility
FROM volatility_assumptions
WHERE recorded_at >= '2023-10-10 10:00:00' AND recorded_at < '2023-10-11 10:00:00';

SELECT report_id, report_format
FROM pricing_reports
WHERE generated_by = 1;

SELECT api_name, last_synced
FROM api_integrations
WHERE api_key = 'key456';

SELECT strike_price
FROM option_prices
WHERE strike_price > (SELECT AVG(strike_price) FROM option_prices);

SELECT option_type, AVG(strike_price) AS average_strike_price
FROM option_prices
GROUP BY option_type;

SELECT strategy_name 
FROM trading_strategies
WHERE strategy_id = 1;
